  // app/javascript/themes/theme-manager.ts
  var ThemeManager = class {
    _current = "synthwave-2077";
    listeners = [];
    get current() {
      return this._current;
    }
    currentExtension() {
      return this.extensionFor(this._current);
    }
    setTheme(id3) {
      this._current = id3;
      this.listeners.forEach((fn5) => fn5(id3));
      document.documentElement.setAttribute("data-theme", id3);
      this.persistTheme(id3);
    }
    onChange(fn5) {
      this.listeners.push(fn5);
    }
    extensionFor(id3) {
      switch (id3) {
        case "synthwave-2077":
          return synthwave2077;
        case "nordic-frost":
          return nord;
        case "obsidian":
          return obsidian;
        case "solarized-dark":
          return solarizedDark;
        case "solarized-light":
          return solarizedLight;
        case "dracula":
          return dracula;
        case "one-dark":
          return oneDark;
        case "protanopia-dark":
          return protanopiaDark;
        case "protanopia-light":
          return protanopiaLight;
        case "deuteranopia-dark":
          return deuteranopiaDark;
        case "deuteranopia-light":
          return deuteranopiaLight;
        case "tritanopia-dark":
          return tritanopiaDark;
        case "tritanopia-light":
          return tritanopiaLight;
        case "achromatopsia-dark":
          return achromatopsiaDark;
        case "achromatopsia-light":
          return achromatopsiaLight;
        default:
          return synthwave2077;
      }
    }
    persistTheme(id3) {
      fetch("/settings", {
        method: "PATCH",
        headers: { "Content-Type": "application/json", "X-CSRF-Token": this.csrfToken() },
        body: JSON.stringify({ theme: id3 })
      }).catch(console.error);
    }
    csrfToken() {
      return document.querySelector('meta[name="csrf-token"]')?.content ?? "";
    }
  };

  // app/javascript/utils/tts.ts
  var TTSController = class {
    editor;
    synth = window.speechSynthesis;
    speaking = false;
    rate = 0.95;
    selectedVoice = null;
    constructor(editor) {
      this.editor = editor;
      window.speechSynthesis.onvoiceschanged = () => {
        const voices = this.synth.getVoices();
        if (!this.selectedVoice && voices.length > 0) {
          this.selectedVoice = voices[0] ?? null;
        }
      };
    }
    getVoices() {
      return this.synth.getVoices();
    }
    setVoice(voiceURI) {
      const voices = this.synth.getVoices();
      this.selectedVoice = voices.find((v7) => v7.voiceURI == voiceURI) ?? null;
    }
    setRate(rate) {
      this.rate = rate;
    }
    getRate() {
      return this.rate;
    }
    speak(text) {
      const content2 = text ?? this.editor.getContent();
      if (!content2.trim())
        return;
      this.stop();
      const utterance = new SpeechSynthesisUtterance(content2);
      utterance.rate = this.rate;
      if (this.selectedVoice)
        utterance.voice = this.selectedVoice;
      utterance.onstart = () => {
        this.speaking = true;
      };
      utterance.onend = () => {
        this.speaking = false;
      };
      this.synth.speak(utterance);
    }
    stop() {
      if (this.synth.speaking)
        this.synth.cancel();
      this.speaking = false;
    }
    isSpeaking() {
      return this.speaking;
    }
  };

  // app/javascript/components/git-panel.ts
  var GitPanel = class {
    csrfToken;
    panel;
    overlay;
    repoPath = "";
    constructor() {
      this.csrfToken = document.querySelector('meta[name="csrf-token"]')?.content ?? "";
      this.panel = this.buildPanel();
      this.overlay = this.buildOverlay();
      document.body.appendChild(this.overlay);
      document.body.appendChild(this.panel);
    }
    buildOverlay() {
      const overlay = document.createElement("div");
      overlay.id = "git-overlay";
      overlay.style.cssText = `
      display: none;
      position: fixed;
      inset: 0;
      background: rgba(0,0,0,0.5);
      z-index: 99;
    `;
      overlay.addEventListener("click", () => this.close());
      return overlay;
    }
    buildPanel() {
      const panel = document.createElement("div");
      panel.id = "git-panel";
      panel.style.cssText = `
      display: none;
      position: fixed;
      top: 0;
      right: 0;
      width: 360px;
      height: 100dvh;
      background: var(--bg-panel);
      border-left: 1px solid var(--accent-green);
      z-index: 100;
      overflow-y: auto;
      padding: 1.5rem;
      box-shadow: -4px 0 30px #39ff1433;
      font-family: var(--font-ui);
      color: var(--fg);
    `;
      return panel;
    }
    async open() {
      this.panel.style.display = "block";
      this.overlay.style.display = "block";
      await this.render();
    }
    close() {
      this.panel.style.display = "none";
      this.overlay.style.display = "none";
    }
    async render() {
      this.panel.innerHTML = `
      <div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:1.5rem;">
        <span style="color:var(--accent-green); font-size:0.85rem; letter-spacing:0.1em; text-transform:uppercase;">Git</span>
        <button id="git-close" style="background:none; border:none; color:var(--fg-muted); cursor:pointer; font-size:1.2rem;">\xD7</button>
      </div>

      <div class="git-section">
        <label class="git-label">Repository Path</label>
        <div style="display:flex; gap:0.5rem;">
          <input type="text" id="git-path" placeholder="/path/to/your/repo"
            style="flex:1; background:var(--bg-surface); border:1px solid var(--border); border-radius:4px;
            padding:0.5rem 0.75rem; color:var(--fg); font-family:var(--font-mono); font-size:0.8rem; outline:none;" />
          <button id="git-load" style="background:var(--accent-green); border:none; border-radius:4px;
            padding:0.5rem 0.75rem; color:var(--bg); font-family:var(--font-mono); font-size:0.8rem; cursor:pointer;">Load</button>
        </div>
      </div>

      <div class="git-section" id="git-status-section" style="display:none;">
        <label class="git-label">Status</label>
        <pre id="git-status-output" style="background:var(--bg-surface); border-radius:4px; padding:0.75rem;
          font-size:0.75rem; overflow-x:auto; white-space:pre-wrap; max-height:200px; overflow-y:auto;"></pre>
        <button id="git-refresh" style="margin-top:0.5rem; background:transparent; border:1px solid var(--border);
          border-radius:4px; padding:0.3rem 0.75rem; color:var(--fg-muted); font-family:var(--font-mono);
          font-size:0.75rem; cursor:pointer;">\u21BB Refresh</button>
      </div>

      <div class="git-section" id="git-diff-section" style="display:none;">
        <label class="git-label">Diff</label>
        <pre id="git-diff-output" style="background:var(--bg-surface); border-radius:4px; padding:0.75rem;
          font-size:0.75rem; overflow-x:auto; white-space:pre-wrap; max-height:250px; overflow-y:auto;"></pre>
      </div>

      <div class="git-section" id="git-commit-section" style="display:none;">
        <label class="git-label">Commit</label>
        <input type="text" id="git-commit-message" placeholder="Commit message..."
          style="width:100%; background:var(--bg-surface); border:1px solid var(--border); border-radius:4px;
          padding:0.5rem 0.75rem; color:var(--fg); font-family:var(--font-mono); font-size:0.8rem; outline:none;
          margin-bottom:0.5rem;" />
        <button id="git-commit-btn" style="width:100%; background:var(--accent-green); border:none; border-radius:4px;
          padding:0.5rem; color:var(--bg); font-family:var(--font-mono); font-size:0.85rem; cursor:pointer;">
          Commit All Changes
        </button>
        <div id="git-commit-result" style="margin-top:0.5rem; font-size:0.75rem; color:var(--fg-muted);"></div>
      </div>
    `;
      const style = document.getElementById("git-panel-styles");
      if (!style) {
        const s = document.createElement("style");
        s.id = "git-panel-styles";
        s.textContent = `
        .git-section { margin-bottom: 1.5rem; }
        .git-label {
          display: block;
          font-size: 0.75rem;
          color: var(--fg-muted);
          text-transform: uppercase;
          letter-spacing: 0.08em;
          margin-bottom: 0.5rem;
        }
      `;
        document.head.appendChild(s);
      }
      document.getElementById("git-close").addEventListener("click", () => this.close());
      const pathInput = document.getElementById("git-path");
      const loadBtn = document.getElementById("git-load");
      if (this.repoPath)
        pathInput.value = this.repoPath;
      loadBtn.addEventListener("click", async () => {
        const path = pathInput.value.trim();
        if (!path)
          return;
        this.repoPath = path;
        await this.loadRepo(path);
      });
    }
    async loadRepo(path) {
      try {
        const [statusText, diffText] = await Promise.all([
          this.status(path),
          this.diff(path)
        ]);
        const statusSection = document.getElementById("git-status-section");
        const diffSection = document.getElementById("git-diff-section");
        const commitSection = document.getElementById("git-commit-section");
        const statusEl = document.getElementById("git-status-output");
        const diffEl = document.getElementById("git-diff-output");
        statusSection.style.display = "block";
        diffSection.style.display = "block";
        commitSection.style.display = "block";
        statusEl.textContent = statusText || "(nothing to commit)";
        diffEl.textContent = diffText || "(no changes)";
        document.getElementById("git-refresh").addEventListener("click", () => this.loadRepo(path));
        const commitBtn = document.getElementById("git-commit-btn");
        const commitMsg = document.getElementById("git-commit-message");
        const commitResult = document.getElementById("git-commit-result");
        commitBtn.addEventListener("click", async () => {
          const message = commitMsg.value.trim();
          if (!message) {
            commitResult.textContent = "Please enter a commit message.";
            return;
          }
          try {
            await this.commit(path, message);
            commitResult.style.color = "var(--accent-green)";
            commitResult.textContent = "\u2713 Committed successfully";
            commitMsg.value = "";
            await this.loadRepo(path);
          } catch (e) {
            commitResult.style.color = "var(--accent-pink)";
            commitResult.textContent = `Error: ${e.message}`;
          }
        });
      } catch (e) {
        const statusSection = document.getElementById("git-status-section");
        statusSection.style.display = "block";
        document.getElementById("git-status-output").textContent = `Error: ${e.message}`;
      }
    }
    async status(path) {
      const res = await fetch(`/git/status?path=${encodeURIComponent(path)}`, {
        headers: { "X-CSRF-Token": this.csrfToken }
      });
      if (!res.ok)
        throw new Error("Git status failed");
      const data2 = await res.json();
      return data2.output;
    }
    async diff(path) {
      const res = await fetch(`/git/diff?path=${encodeURIComponent(path)}`, {
        headers: { "X-CSRF-Token": this.csrfToken }
      });
      if (!res.ok)
        throw new Error("Git diff failed");
      const data2 = await res.json();
      return data2.output;
    }
    async commit(path, message) {
      const res = await fetch("/git/commit", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          "X-CSRF-Token": this.csrfToken
        },
        body: JSON.stringify({ path, message })
      });
      if (!res.ok)
        throw new Error("Commit failed");
    }
  };

  // app/javascript/components/live-preview.ts
  var LivePreview = class {
    editor;
    frame = null;
    debounceTimer = null;
    constructor(editor) {
      this.editor = editor;
      this.frame = document.getElementById("preview-frame");
    }
    enable() {
      this.update();
    }
    update() {
      if (this.debounceTimer)
        clearTimeout(this.debounceTimer);
      this.debounceTimer = setTimeout(() => this.render(), 300);
    }
    render() {
      if (!this.frame)
        return;
      const content2 = this.editor.getContent();
      const doc2 = this.frame.contentDocument;
      if (!doc2)
        return;
      doc2.open();
      doc2.write(content2);
      doc2.close();
    }
    disable() {
      if (this.debounceTimer)
        clearTimeout(this.debounceTimer);
    }
  };

  // app/javascript/components/tutorial.ts
  var APP_VERSION = "3.0.0";
  var TUTORIAL_KEY = "clearcode_tutorial_version";
  var TutorialSystem = class {
    seen;
    constructor() {
      const stored = localStorage.getItem(TUTORIAL_KEY);
      this.seen = stored === APP_VERSION;
      if (!this.seen)
        this.show();
    }
    show() {
      console.info("[ClearCode] Tutorial: version", APP_VERSION);
    }
    dismiss() {
      localStorage.setItem(TUTORIAL_KEY, APP_VERSION);
      this.seen = true;
    }
  };

  // app/javascript/components/file-manager.ts
  var FileManager = class {
    editor;
    currentFile = null;
    files = [];
    csrfToken;
    sidebar;
    statusLang;
    projectFilter = null;
    constructor(editor) {
      this.editor = editor;
      this.csrfToken = document.querySelector('meta[name="csrf-token"]')?.content ?? "";
      this.sidebar = document.getElementById("sidebar");
      this.statusLang = document.getElementById("status-lang");
      this.bindKeyboard();
      setInterval(() => {
        if (this.currentFile)
          this.saveCurrentFile();
      }, 5 * 60 * 1e3);
    }
    setProjectFilter(projectId) {
      this.projectFilter = projectId;
    }
    async loadFiles() {
      const url = this.projectFilter ? `/code_files?project_id=${this.projectFilter}` : "/code_files";
      const res = await fetch(url, {
        headers: { "X-CSRF-Token": this.csrfToken }
      });
      this.files = await res.json();
      this.renderSidebar();
    }
    async openFile(id3) {
      const res = await fetch(`/code_files/${id3}`, {
        headers: { "X-CSRF-Token": this.csrfToken }
      });
      const file = await res.json();
      this.currentFile = file;
      this.editor.setContent(file.content ?? "");
      this.editor.setLanguage(file.name);
      if (this.statusLang)
        this.statusLang.textContent = file.language;
    }
    async newFile(name2) {
      const res = await fetch("/code_files", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          "X-CSRF-Token": this.csrfToken
        },
        body: JSON.stringify({ code_file: { name: name2, content: "", project_id: this.projectFilter } })
      });
      const file = await res.json();
      this.files.push(file);
      this.renderSidebar();
      await this.openFile(file.id);
    }
    async saveCurrentFile() {
      if (!this.currentFile)
        return;
      const content2 = this.editor.getContent();
      await fetch(`/code_files/${this.currentFile.id}`, {
        method: "PATCH",
        headers: {
          "Content-Type": "application/json",
          "X-CSRF-Token": this.csrfToken
        },
        body: JSON.stringify({ code_file: { content: content2 } })
      });
      this.showSavedFeedback();
    }
    showSavedFeedback() {
      console.log("[ClearCode] showSavedFeedback called");
      const el5 = document.getElementById("status-cursor");
      if (!el5)
        return;
      const original = el5.textContent;
      el5.textContent = "\u2713 Saved";
      el5.style.color = "var(--accent-cyan)";
      setTimeout(() => {
        el5.textContent = original;
        el5.style.color = "";
      }, 3e3);
    }
    async deleteFile(id3) {
      await fetch(`/code_files/${id3}`, {
        method: "DELETE",
        headers: { "X-CSRF-Token": this.csrfToken }
      });
      this.files = this.files.filter((f7) => f7.id !== id3);
      if (this.currentFile?.id === id3) {
        this.currentFile = null;
        this.editor.setContent("");
      }
      this.renderSidebar();
    }
    async renameFile(id3, newName) {
      const res = await fetch(`/code_files/${id3}`, {
        method: "PATCH",
        headers: {
          "Content-Type": "application/json",
          "X-CSRF-Token": this.csrfToken
        },
        body: JSON.stringify({ code_file: { name: newName } })
      });
      const updated = await res.json();
      this.files = this.files.map((f7) => f7.id === id3 ? { ...f7, name: updated.name, language: updated.language } : f7);
      if (this.currentFile?.id === id3) {
        this.currentFile = { ...this.currentFile, name: updated.name };
        this.editor.setLanguage(updated.name);
        if (this.statusLang)
          this.statusLang.textContent = updated.language;
      }
      this.renderSidebar();
    }
    renderSidebar() {
      if (!this.sidebar)
        return;
      this.sidebar.innerHTML = `
      <div class="sidebar-header">
        <button class="btn-new" id="btn-new-file">+ New File</button>
        <button class="btn-save" id="btn-save-file">\u2193 Save</button>
      </div>
      <ul class="file-list">
        ${this.files.map((f7) => `
          <li class="file-item ${this.currentFile?.id === f7.id ? "active" : ""}" data-id="${f7.id}">
            <span class="file-name">${f7.name}</span>
            <button class="btn-delete" data-id="${f7.id}">\xD7</button>
          </li>
        `).join("")}
      </ul>
    `;
      document.getElementById("btn-new-file")?.addEventListener("click", () => {
        const name2 = prompt("File name (e.g. index.ts):");
        if (name2)
          this.newFile(name2);
      });
      document.getElementById("btn-save-file")?.addEventListener("click", () => {
        this.saveCurrentFile();
      });
      this.sidebar.querySelectorAll(".file-item .file-name").forEach((el5) => {
        el5.addEventListener("click", () => {
          const id3 = Number(el5.closest(".file-item").dataset["id"]);
          this.openFile(id3);
        });
        el5.addEventListener("dblclick", (e) => {
          e.stopPropagation();
          const item = el5.closest(".file-item");
          const id3 = Number(item.dataset["id"]);
          const current = el5.textContent ?? "";
          const input = document.createElement("input");
          input.value = current;
          input.className = "file-rename-input";
          input.style.cssText = `
          background: var(--bg-surface);
          border: 1p solid var(--sccent-cyan);
          color: var(--fg);
          font-family: var(--font-mono);
          font-size: 12px;
          padding: 0 4px;
          border-radius: 3px;
          width: 100%;
          outline: none;
        `;
          el5.replaceWith(input);
          input.focus();
          input.select();
          const commit = () => {
            const newName = input.value.trim();
            if (newName && newName !== current) {
              this.renameFile(id3, newName);
            } else {
              this.renderSidebar();
            }
          };
          input.addEventListener("keydown", (e4) => {
            e4.stopPropagation();
            if (e4.key === "Enter")
              commit();
            if (e4.key === "Escape")
              this.renderSidebar();
          });
          input.addEventListener("blur", commit);
        });
      });
      this.sidebar.querySelectorAll(".btn-delete").forEach((el5) => {
        el5.addEventListener("click", (e) => {
          e.stopPropagation();
          const id3 = Number(el5.dataset["id"]);
          if (confirm(`Delete file?`))
            this.deleteFile(id3);
        });
      });
    }
    bindKeyboard() {
      document.addEventListener("keydown", (e) => {
        if ((e.metaKey || e.ctrlKey) && e.key === "s") {
          e.preventDefault();
          this.saveCurrentFile();
        }
      });
    }
  };

